// /frontend/src/components/Composer.jsx
import React, { useRef, useState } from "react";

export default function Composer({ onPost, maxLen=280, placeholder="What’s happening?" }) {
  const [text, setText] = useState("");
  const [files, setFiles] = useState([]); // [{name,url,type}]
  const [quoteUrl, setQuoteUrl] = useState("");
  const inputRef = useRef(null);

  const count = text.length;
  const over = count > maxLen;

  const pickFiles = (e) => {
    const list = Array.from(e.target.files || []);
    const next = list.slice(0, 4).map(f => ({
      name: f.name,
      type: f.type,
      // base64 preview for local; backend flow will replace with uploaded URLs
      url: URL.createObjectURL(f),
      _file: f,
    }));
    setFiles(x => [...x, ...next].slice(0,4));
    inputRef.current.value = ""; // allow re-pick same file
  };

  const removeMedia = (i) => setFiles(f => f.filter((_,idx)=>idx!==i));

  const extractHashtags = (t) =>
    Array.from(new Set((t.match(/#[\p{L}\d_]+/gu) || []).map(s => s.slice(1).toLowerCase())));

  const submit = async () => {
    const t = text.trim();
    if (!t || over) return;

    // Prepare media payload: if backend exists, you’ll upload _file(s) first and use returned URLs
    const media = files.map(({url,type,name,_file}) => ({ url, type, name, _file }));
    const hashtags = extractHashtags(t);
    const payload = { text: t, media, quoteOf: quoteUrl || null, hashtags };

    await onPost?.(payload);
    setText("");
    setFiles([]);
    setQuoteUrl("");
  };

  return (
    <div className="flex gap-3">
      <div className="h-10 w-10 rounded-full bg-white/20 shrink-0 grid place-items-center">🟣</div>

      <div className="flex-1">
        <textarea
          value={text}
          onChange={(e)=>setText(e.target.value)}
          rows={3}
          className="w-full bg-transparent outline-none resize-none text-sm"
          placeholder={placeholder}
          maxLength={maxLen + 100}
        />

        {/* Media previews */}
        {!!files.length && (
          <div className="mt-2 grid grid-cols-2 gap-2">
            {files.map((f,i)=>(
              <div key={i} className="relative">
                {f.type.startsWith("image/") ? (
                  <img src={f.url} alt="" className="rounded-lg object-cover w-full h-28" />
                ) : (
                  <video src={f.url} className="rounded-lg w-full h-28 object-cover" controls />
                )}
                <button className="absolute top-1 right-1 text-xs bg-black/60 px-2 py-0.5 rounded"
                        onClick={()=>removeMedia(i)}>✕</button>
              </div>
            ))}
          </div>
        )}

        {/* Quote post (paste a URL or post id later) */}
        <div className="flex items-center gap-2 mt-2">
          <input
            value={quoteUrl}
            onChange={(e)=>setQuoteUrl(e.target.value)}
            className="flex-1 bg-white/10 rounded px-2 py-1 text-xs outline-none"
            placeholder="Quote a link (optional)…"
          />
          <label className="text-xs px-2 py-1 rounded bg-white/10 cursor-pointer">
            + Media
            <input ref={inputRef} type="file" multiple accept="image/*,video/*" hidden onChange={pickFiles} />
          </label>
        </div>

        <div className="flex items-center justify-between mt-2">
          <div className="text-xs opacity-60">{count}/{maxLen}</div>
          <button
            onClick={submit}
            disabled={!text.trim() || over}
            className="px-3 py-1.5 rounded-lg bg-white/15 ring-1 ring-white/10 disabled:opacity-50 text-sm"
          >
            Post
          </button>
        </div>
      </div>
    </div>
  );
}
